import { spawn } from "node:child_process";

export interface AgentBrowserInput {
  args: string[];
  sessionName?: string;
  allowedDomains?: string[];
  maxOutputChars?: number;
}

export interface AgentBrowserResult {
  ok: boolean;
  command: string[];
  stdout: string;
  stderr: string;
  exitCode: number | null;
}

export async function runAgentBrowser(input: AgentBrowserInput): Promise<AgentBrowserResult> {
  const command = process.env.AGENT_BROWSER_BIN ?? "agent-browser";
  const args = [
    ...(input.sessionName ? ["--session-name", input.sessionName] : []),
    ...input.args,
  ];
  const result = await run(command, args, {
    AGENT_BROWSER_ALLOWED_DOMAINS: input.allowedDomains?.join(","),
    AGENT_BROWSER_CONTENT_BOUNDARIES: "1",
  });
  const max = input.maxOutputChars ?? 12000;

  return {
    ...result,
    stdout: result.stdout.slice(0, max),
    stderr: result.stderr.slice(0, max),
  };
}

async function run(command: string, args: string[], env: Record<string, string | undefined>): Promise<AgentBrowserResult> {
  return new Promise((resolve) => {
    const child = spawn(command, args, {
      env: { ...process.env, ...withoutUndefined(env) },
      stdio: ["ignore", "pipe", "pipe"],
    });
    let stdout = "";
    let stderr = "";

    child.stdout.on("data", (chunk) => {
      stdout += String(chunk);
    });
    child.stderr.on("data", (chunk) => {
      stderr += String(chunk);
    });
    child.on("error", (error) => {
      resolve({
        ok: false,
        command: [command, ...args],
        stdout,
        stderr: error.message,
        exitCode: null,
      });
    });
    child.on("close", (code) => {
      resolve({
        ok: code === 0,
        command: [command, ...args],
        stdout,
        stderr,
        exitCode: code,
      });
    });
  });
}

function withoutUndefined(values: Record<string, string | undefined>): Record<string, string> {
  return Object.fromEntries(Object.entries(values).filter((entry): entry is [string, string] => entry[1] !== undefined));
}

import { mkdir, writeFile } from "node:fs/promises";
import path from "node:path";

export interface QaReportInput {
  targetUrl: string;
  result: "passed" | "blocked" | "failed" | "incomplete";
  summary: string;
  checked: string[];
  findings: string[];
  evidence: string[];
  nextActions: string[];
  reportPath?: string;
}

export async function writeQaReport(input: QaReportInput) {
  const reportPath = input.reportPath ?? defaultReportPath(input.targetUrl);
  const report = renderQaReport(input);
  await mkdir(path.dirname(reportPath), { recursive: true });
  await writeFile(reportPath, report, "utf8");

  return {
    reportPath,
    report,
  };
}

function renderQaReport(input: QaReportInput): string {
  return `# Website QA Report

Target: ${input.targetUrl}
Checked: ${new Date().toISOString()}
Result: ${input.result}

## Summary

${input.summary}

## What Was Checked

${list(input.checked)}

## Findings

${list(input.findings)}

## Evidence

${list(input.evidence)}

## Recommended Next Actions

${list(input.nextActions)}
`;
}

function list(items: string[]): string {
  return items.length ? items.map((item) => `- ${item}`).join("\n") : "- None";
}

function defaultReportPath(url: string): string {
  const safe = url.replace(/^https?:\/\//i, "").replace(/[^a-z0-9]+/gi, "-").replace(/^-|-$/g, "").toLowerCase();
  return `reports/${safe || "website"}-${new Date().toISOString().slice(0, 10)}.md`;
}

import { defineAgent } from "eve";

export default defineAgent({
  model: "anthropic/claude-sonnet-4.6",
  description:
    "Runs browser-driven QA on web app flows such as signup and onboarding, captures evidence, and writes concise Markdown reports."
});

import { defineTool } from "eve/tools";
import { z } from "zod";

import { runAgentBrowser } from "../lib/browser.js";

const inputSchema = z.object({
  args: z.array(z.string()).min(1).describe('agent-browser arguments, for example ["open", "https://example.com"] or ["snapshot", "-i"].'),
  sessionName: z.string().optional().describe("Optional persistent browser session name for this QA run."),
  allowedDomains: z.array(z.string()).optional().describe("Optional domain allowlist, for example ['example.com', '*.example.com']."),
  maxOutputChars: z.number().int().positive().optional().describe("Maximum stdout/stderr characters to return."),
});

type AgentBrowserToolInput = z.infer<typeof inputSchema>;

export default defineTool({
  description:
    "Run one agent-browser CLI command for interactive website QA. Use snapshot -i to discover refs, then click/fill/wait/screenshot as needed.",
  inputSchema,
  async execute(input: AgentBrowserToolInput) {
    return runAgentBrowser(input);
  },
});

import { defineTool } from "eve/tools";
import { z } from "zod";

import { writeQaReport } from "../lib/report.js";

const inputSchema = z.object({
  targetUrl: z.string().min(1),
  result: z.enum(["passed", "blocked", "failed", "incomplete"]),
  summary: z.string().min(1),
  checked: z.array(z.string()),
  findings: z.array(z.string()),
  evidence: z.array(z.string()),
  nextActions: z.array(z.string()),
  reportPath: z.string().optional(),
});

type WriteQaReportToolInput = z.infer<typeof inputSchema>;

export default defineTool({
  description: "Write the final Markdown QA report after completing the browser-driven test flow.",
  inputSchema,
  async execute(input: WriteQaReportToolInput) {
    return writeQaReport(input);
  },
});
